package main

import (
	"bytes"
	"fmt"
	"io"
	"os"
	"os/exec"
)

// QuerySLBAndExport queries SLB information using aliyun CLI and jq, 
// exports the result to a file, and returns the output content.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Create the aliyun command: aliyun slb DescribeLoadBalancers --LoadBalancerName <name>
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command: jq '.LoadBalancers.LoadBalancer[]'
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe to connect stdout of cmdAliyun to stdin of cmdJq
	pr, pw := io.Pipe()
	cmdAliyun.Stdout = pw
	cmdJq.Stdin = pr

	// Buffer to capture the output of jq
	var outputBuf bytes.Buffer
	cmdJq.Stdout = &outputBuf

	// Start the aliyun command
	if err := cmdAliyun.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start the jq command
	if err := cmdJq.Start(); err != nil {
		// Clean up the aliyun command if jq fails to start
		cmdAliyun.Process.Kill()
		cmdAliyun.Wait()
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for the aliyun command to finish in a goroutine, then close the pipe writer
	aliErrChan := make(chan error, 1)
	go func() {
		aliErrChan <- cmdAliyun.Wait()
		pw.Close()
	}()

	// Wait for the jq command to finish
	if err := cmdJq.Wait(); err != nil {
		// Drain the error channel to avoid goroutine leak
		<-aliErrChan
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// Check if aliyun command succeeded
	if err := <-aliErrChan; err != nil {
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	result := outputBuf.String()

	// Write the result to the output file
	if err := os.WriteFile(outputFile, []byte(result), 0644); err != nil {
		return "", fmt.Errorf("failed to write to output file %s: %w", outputFile, err)
	}

	return result, nil
}

func main() {
	// Example usage: go run main.go <loadBalancerName> <outputFile>
	if len(os.Args) == 3 {
		result, err := QuerySLBAndExport(os.Args[1], os.Args[2])
		if err != nil {
			fmt.Fprintf(os.Stderr, "Error: %v\n", err)
			os.Exit(1)
		}
		fmt.Printf("Successfully exported SLB information to %s\n", os.Args[2])
		fmt.Println("Output content:")
		fmt.Println(result)
	} else {
		fmt.Println("Usage: go run main.go <loadBalancerName> <outputFile>")
	}
}

