func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Create output file
	file, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file %s: %w", outputFile, err)
	}
	defer file.Close()

	// First command: aliyun slb DescribeLoadBalancers
	cmd1 := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Second command: jq
	cmd2 := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create pipe between commands
	pr, pw := io.Pipe()
	cmd1.Stdout = pw
	cmd2.Stdin = pr

	// Setup output to capture and write to file simultaneously
	var stdoutBuf bytes.Buffer
	cmd2.Stdout = io.MultiWriter(&stdoutBuf, file)

	// Capture stderr from both commands
	var stderrBuf bytes.Buffer
	cmd1.Stderr = &stderrBuf
	cmd2.Stderr = &stderrBuf

	// Start jq first (reader) to avoid blocking on pipe buffer
	if err := cmd2.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq: %w", err)
	}

	// Start aliyun command (writer)
	if err := cmd1.Start(); err != nil {
		pw.Close() // Close pipe to unblock jq
		cmd2.Wait()
		return "", fmt.Errorf("failed to start aliyun: %w", err)
	}

	// Wait for cmd1 in goroutine and close pipe when done
	cmd1Done := make(chan error, 1)
	go func() {
		cmd1Done <- cmd1.Wait()
		pw.Close()
	}()

	// Wait for cmd2 to finish processing
	cmd2Err := cmd2.Wait()

	// Get cmd1 result
	cmd1Err := <-cmd1Done

	// Check errors
	if cmd2Err != nil {
		return stdoutBuf.String(), fmt.Errorf("jq processing failed: %w, stderr: %s", cmd2Err, stderrBuf.String())
	}
	if cmd1Err != nil {
		return stdoutBuf.String(), fmt.Errorf("aliyun command failed: %w, stderr: %s", cmd1Err, stderrBuf.String())
	}

	return stdoutBuf.String(), nil
}

