// QuerySLBAndExport queries SLB information using aliyun CLI and exports it to a JSON file using jq.
// It executes the equivalent of: aliyun slb DescribeLoadBalancers --LoadBalancerName NAME | jq '.LoadBalancers.LoadBalancer[]' > outputFile
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Create the aliyun command: aliyun slb DescribeLoadBalancers --LoadBalancerName <name>
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command: jq '.LoadBalancers.LoadBalancer[]'
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe to connect aliyun's stdout to jq's stdin
	pipe, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}
	cmdJq.Stdin = pipe

	// Open output file for jq's stdout (equivalent to > output.json)
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file %s: %w", outputFile, err)
	}
	defer outFile.Close()
	cmdJq.Stdout = outFile

	// Capture stderr for error reporting
	var aliyunStderr, jqStderr bytes.Buffer
	cmdAliyun.Stderr = &aliyunStderr
	cmdJq.Stderr = &jqStderr

	// Start aliyun command first
	if err := cmdAliyun.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start jq command
	if err := cmdJq.Start(); err != nil {
		// Clean up aliyun process if jq fails to start to avoid zombie processes
		cmdAliyun.Process.Kill()
		cmdAliyun.Wait()
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for aliyun to finish (this closes the pipe writer when done)
	if err := cmdAliyun.Wait(); err != nil {
		// Ensure jq also finishes to clean up properly
		cmdJq.Wait()
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, aliyunStderr.String())
	}

	// Wait for jq to finish processing the input
	if err := cmdJq.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", err, jqStderr.String())
	}

	return fmt.Sprintf("Successfully exported SLB '%s' data to %s", loadBalancerName, outputFile), nil
}

func main() {
	// Example usage: go run main.go <load-balancer-name> <output-file>
	if len(os.Args) != 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <load-balancer-name> <output-file>\n", os.Args[0])
		os.Exit(1)
	}

	result, err := QuerySLBAndExport(os.Args[1], os.Args[2])
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}
	fmt.Println(result)
}

