package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Input validation
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Create the aliyun command: aliyun slb DescribeLoadBalancers --LoadBalancerName <name>
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command: jq '.LoadBalancers.LoadBalancer[]'
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe to connect aliyun stdout to jq stdin
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}
	jqCmd.Stdin = aliyunStdout

	// Set up buffers to capture outputs
	var jqOutput bytes.Buffer
	var aliyunStderr bytes.Buffer
	var jqStderr bytes.Buffer

	jqCmd.Stdout = &jqOutput
	aliyunCmd.Stderr = &aliyunStderr
	jqCmd.Stderr = &jqStderr

	// Start jq command first so it's ready to consume input
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		// Clean up the jq process if aliyun fails to start
		jqCmd.Process.Kill()
		jqCmd.Wait()
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Wait for aliyun command to complete
	if err := aliyunCmd.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, aliyunStderr.String())
	}

	// Wait for jq command to complete processing
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", err, jqStderr.String())
	}

	output := jqOutput.String()

	// Write the output to the specified file
	if err := os.WriteFile(outputFile, []byte(output), 0644); err != nil {
		return output, fmt.Errorf("failed to write output to file %s: %w", outputFile, err)
	}

	return output, nil
}

