package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Input validation
	if strings.TrimSpace(loadBalancerName) == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if strings.TrimSpace(outputFile) == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Check for null bytes which could cause argument truncation
	if strings.Contains(loadBalancerName, "\x00") {
		return "", fmt.Errorf("loadBalancerName contains null bytes")
	}
	if strings.Contains(outputFile, "\x00") {
		return "", fmt.Errorf("outputFile contains null bytes")
	}

	// Prevent directory traversal - ensure output file is within current directory tree
	cleanPath := filepath.Clean(outputFile)
	if !filepath.IsLocal(cleanPath) {
		return "", fmt.Errorf("output file path must be local (no directory traversal)")
	}

	// Execute aliyun command safely without shell
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	aliyunOutput, err := aliyunCmd.Output()
	if err != nil {
		var stderr []byte
		if exitErr, ok := err.(*exec.ExitError); ok {
			stderr = exitErr.Stderr
		}
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, string(stderr))
	}

	// Execute jq command safely without shell
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = bytes.NewReader(aliyunOutput)
	jqOutput, err := jqCmd.Output()
	if err != nil {
		var stderr []byte
		if exitErr, ok := err.(*exec.ExitError); ok {
			stderr = exitErr.Stderr
		}
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", err, string(stderr))
	}

	// Write to output file with secure permissions (owner read/write only)
	if err := os.WriteFile(outputFile, jqOutput, 0600); err != nil {
		return string(jqOutput), fmt.Errorf("failed to write output file: %w", err)
	}

	return string(jqOutput), nil
}

