// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate inputs
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Create the aliyun command with arguments as separate strings to avoid shell injection
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe to connect stdout of aliyun to stdin of jq
	pipe, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}
	cmdJq.Stdin = pipe

	// Capture stdout of jq command
	var stdoutBuf bytes.Buffer
	cmdJq.Stdout = &stdoutBuf

	// Capture stderr for error reporting
	var aliyunStderr, jqStderr bytes.Buffer
	cmdAliyun.Stderr = &aliyunStderr
	cmdJq.Stderr = &jqStderr

	// Start the aliyun command
	if err := cmdAliyun.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start the jq command
	if err := cmdJq.Start(); err != nil {
		// Ensure aliyun process is cleaned up if jq fails to start
		cmdAliyun.Process.Kill()
		cmdAliyun.Wait()
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for aliyun command to complete
	if err := cmdAliyun.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, aliyunStderr.String())
	}

	// Wait for jq command to complete
	if err := cmdJq.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", err, jqStderr.String())
	}

	// Get the output
	output := stdoutBuf.String()

	// Write to output file
	if err := os.WriteFile(outputFile, []byte(output), 0644); err != nil {
		return output, fmt.Errorf("failed to write to output file: %w", err)
	}

	return output, nil
}

