	r, w := io.Pipe()
	cmd1.Stdout = w
	cmd2.Stdin = r

	// Capture stderr for error reporting
	var cmd1Stderr, cmd2Stderr bytes.Buffer
	cmd1.Stderr = &cmd1Stderr
	cmd2.Stderr = &cmd2Stderr

