package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Input validation
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Create the aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Connect the commands with a pipe
	pipe, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}
	jqCmd.Stdin = pipe

	// Set up output buffers
	var stdoutBuf bytes.Buffer
	var stderrBuf bytes.Buffer
	jqCmd.Stdout = &stdoutBuf
	aliyunCmd.Stderr = &stderrBuf
	jqCmd.Stderr = &stderrBuf

	// Start jq first (it will wait for input from the pipe)
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Run aliyun command (this waits for aliyun to finish writing to the pipe)
	if err := aliyunCmd.Run(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, stderrBuf.String())
	}

	// Wait for jq to finish processing the input
	if err := jqCmd.Wait(); err != nil {
		return stdoutBuf.String(), fmt.Errorf("jq command failed: %w, stderr: %s", err, stderrBuf.String())
	}

	output := stdoutBuf.String()

	// Write output to file
	if err := os.WriteFile(outputFile, []byte(output), 0644); err != nil {
		return output, fmt.Errorf("failed to write output file: %w", err)
	}

	return output, nil
}

