package main

import (
	"bytes"
	"fmt"
	"io"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Input validation
	if strings.TrimSpace(loadBalancerName) == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}

	if strings.TrimSpace(outputFile) == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Validate outputFile to prevent directory traversal attacks
	cleanPath := filepath.Clean(outputFile)
	if strings.Contains(cleanPath, "..") {
		return "", fmt.Errorf("invalid outputFile: path traversal detected")
	}

	// Create output directory if it doesn't exist
	dir := filepath.Dir(cleanPath)
	if err := os.MkdirAll(dir, 0750); err != nil {
		return "", fmt.Errorf("failed to create output directory: %w", err)
	}

	// Open output file with restricted permissions
	file, err := os.OpenFile(cleanPath, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, 0640)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer file.Close()

	// Command 1: aliyun slb DescribeLoadBalancers --LoadBalancerName <name>
	// Arguments are passed as separate strings to avoid shell injection
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Command 2: jq '.LoadBalancers.LoadBalancer[]'
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create pipe to connect cmdAliyun stdout to cmdJq stdin
	pipe, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}
	cmdJq.Stdin = pipe

	// Capture stderr for error reporting
	var aliyunStderr, jqStderr bytes.Buffer
	cmdAliyun.Stderr = &aliyunStderr
	cmdJq.Stderr = &jqStderr

	// Use MultiWriter to write to both file and buffer (to return the content)
	var outputBuf bytes.Buffer
	cmdJq.Stdout = io.MultiWriter(file, &outputBuf)

	// Start jq first (it will wait for input on stdin)
	if err := cmdJq.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq: %w", err)
	}

	// Start aliyun command
	if err := cmdAliyun.Start(); err != nil {
		// Clean up jq process if aliyun fails to start
		if cmdJq.Process != nil {
			cmdJq.Process.Kill()
			cmdJq.Wait()
		}
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Wait for aliyun command to complete
	if err := cmdAliyun.Wait(); err != nil {
		// jq will receive EOF when pipe closes, then exit
		cmdJq.Wait()
		return outputBuf.String(), fmt.Errorf("aliyun command failed: %w, stderr: %s", err, aliyunStderr.String())
	}

	// Wait for jq command to complete processing
	if err := cmdJq.Wait(); err != nil {
		return outputBuf.String(), fmt.Errorf("jq command failed: %w, stderr: %s", err, jqStderr.String())
	}

	return outputBuf.String(), nil
}

