// QuerySLBAndExport queries SLB information using aliyun CLI and jq,
// exports the result to the specified output file, and returns the output content.
// It executes the equivalent of:
// aliyun slb DescribeLoadBalancers --LoadBalancerName <loadBalancerName> | jq '.LoadBalancers.LoadBalancer[]' > <outputFile>
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Create the aliyun command
	cmd1 := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command
	cmd2 := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe to connect cmd1 stdout to cmd2 stdin
	pipe, err := cmd1.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}
	cmd2.Stdin = pipe

	// Capture stderr for error reporting
	var cmd1Stderr bytes.Buffer
	var cmd2Stderr bytes.Buffer
	cmd1.Stderr = &cmd1Stderr
	cmd2.Stderr = &cmd2Stderr

	// Create output file
	file, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file %s: %w", outputFile, err)
	}
	defer file.Close()

	// Buffer to capture output for return value
	var outputBuf bytes.Buffer

	// Write to both file and buffer simultaneously
	cmd2.Stdout = io.MultiWriter(file, &outputBuf)

	// Start cmd2 first to ensure it is reading when cmd1 starts writing
	if err := cmd2.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Start cmd1
	if err := cmd1.Start(); err != nil {
		// Clean up cmd2 to avoid zombie process
		cmd2.Process.Kill()
		cmd2.Wait()
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Wait for cmd1 to complete
	err1 := cmd1.Wait()

	// Wait for cmd2 to complete
	err2 := cmd2.Wait()

	// Check for errors from cmd1
	if err1 != nil {
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err1, cmd1Stderr.String())
	}

	// Check for errors from cmd2
	if err2 != nil {
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", err2, cmd2Stderr.String())
	}

	return outputBuf.String(), nil
}

func main() {
	if len(os.Args) < 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <loadBalancerName> <outputFile>\n", os.Args[0])
		os.Exit(1)
	}

	loadBalancerName := os.Args[1]
	outputFile := os.Args[2]

	result, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Successfully exported SLB information to %s\n", outputFile)
	if len(result) > 0 {
		previewLen := len(result)
		if previewLen > 200 {
			previewLen = 200
		}
		fmt.Printf("Output preview:\n%s\n", result[:previewLen])
	}
}

