// QuerySLBAndExport queries SLB information using aliyun CLI and exports it to a JSON file using jq.
// It executes the pipeline: aliyun slb DescribeLoadBalancers --LoadBalancerName <name> | jq '.LoadBalancers.LoadBalancer[]' > <outputFile>
//
// Parameters:
//   - loadBalancerName: The name of the load balancer to query
//   - outputFile: The path to the output JSON file
//
// Returns:
//   - string: A success message indicating the export completed, or empty string if error
//   - error: Any error encountered during command execution
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Create the aliyun command
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command to filter the output
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe to connect aliyun stdout to jq stdin
	pipe, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun command: %w", err)
	}
	cmdJq.Stdin = pipe

	// Open output file for writing
	file, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file %s: %w", outputFile, err)
	}
	defer file.Close()
	cmdJq.Stdout = file

	// Capture stderr from both commands for error reporting
	var aliyunStderr, jqStderr bytes.Buffer
	cmdAliyun.Stderr = &aliyunStderr
	cmdJq.Stderr = &jqStderr

	// Start jq first (it will block waiting for input from the pipe)
	if err := cmdJq.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Cleanup jq process if we exit early due to errors
	defer func() {
		if cmdJq.Process != nil && (cmdJq.ProcessState == nil || !cmdJq.ProcessState.Exited()) {
			cmdJq.Process.Kill()
		}
	}()

	// Start aliyun command (it will write to the pipe)
	if err := cmdAliyun.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Wait for aliyun to finish writing all output
	if err := cmdAliyun.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, aliyunStderr.String())
	}

	// Wait for jq to finish processing and writing to file
	if err := cmdJq.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", err, jqStderr.String())
	}

	return fmt.Sprintf("Successfully exported SLB information to %s", outputFile), nil
}

func main() {
	// Example usage
