// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Input validation
	if strings.TrimSpace(loadBalancerName) == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if strings.TrimSpace(outputFile) == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Create the aliyun command with arguments passed as separate strings to avoid shell injection
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe to connect stdout of cmdAliyun to stdin of cmdJq
	pipe, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}
	cmdJq.Stdin = pipe

	// Open the output file
	file, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer file.Close()

	// Use MultiWriter to capture output for return value and write to file simultaneously
	var outputBuf bytes.Buffer
	cmdJq.Stdout = io.MultiWriter(&outputBuf, file)

	// Capture stderr from both commands for error reporting
	var aliyunStderr, jqStderr bytes.Buffer
	cmdAliyun.Stderr = &aliyunStderr
	cmdJq.Stderr = &jqStderr

	// Start the aliyun command
	if err := cmdAliyun.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start the jq command
	if err := cmdJq.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for aliyun command to finish
	errAliyun := cmdAliyun.Wait()

	// Wait for jq command to finish (must be called even if aliyun fails to avoid zombie processes)
	errJq := cmdJq.Wait()

	// Check for errors from either command
	if errAliyun != nil {
		errMsg := aliyunStderr.String()
		if jqStderr.Len() > 0 {
			errMsg += "; jq stderr: " + jqStderr.String()
		}
		return errMsg, fmt.Errorf("aliyun command failed: %w", errAliyun)
	}

	if errJq != nil {
		return jqStderr.String(), fmt.Errorf("jq command failed: %w, aliyun stderr: %s", errJq, aliyunStderr.String())
	}

	return outputBuf.String(), nil
}

