// QuerySLBAndExport queries SLB information using aliyun CLI and jq,
// then exports the formatted output to the specified file.
// It returns a success message or an error if any step fails.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the aliyun command
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command for formatting
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Connect stdout of aliyun to stdin of jq via pipe
	stdout, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}
	cmdJq.Stdin = stdout

	// Open output file for writing jq output
	file, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file %s: %w", outputFile, err)
	}
	defer file.Close()
	cmdJq.Stdout = file

	// Start jq command first (it will wait for input from the pipe)
	if err := cmdJq.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Run aliyun command (starts and waits for completion)
	if err := cmdAliyun.Run(); err != nil {
		// Clean up jq process to avoid zombie
		cmdJq.Wait()
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Wait for jq to finish processing all input
	if err := cmdJq.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	return fmt.Sprintf("Successfully exported SLB data to %s", outputFile), nil
}

func main() {
	// Example usage: expects loadBalancerName and outputFile as arguments
	if len(os.Args) < 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <loadBalancerName> <outputFile>\n", os.Args[0])
		os.Exit(1)
	}

	result, err := QuerySLBAndExport(os.Args[1], os.Args[2])
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Println(result)
}

