	cleanPath := filepath.Clean(outputFile)
	if strings.HasPrefix(cleanPath, "..") || strings.Contains(cleanPath, string(filepath.Separator)+"..") {
		return "", fmt.Errorf("invalid output file path: directory traversal detected")
	}

	// Create output file securely
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// First command: aliyun slb DescribeLoadBalancers --LoadBalancerName <loadBalancerName>
	// Arguments are passed separately to prevent shell injection
	cmd1 := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Second command: jq '.LoadBalancers.LoadBalancer[]'
	cmd2 := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create pipe to connect stdout of cmd1 to stdin of cmd2
	pipe, err := cmd1.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}
	cmd2.Stdin = pipe

	// Capture stdout to return it, and also write to file
	var stdoutBuf bytes.Buffer
	cmd2.Stdout = io.MultiWriter(&stdoutBuf, outFile)

