	var stderrBuf bytes.Buffer
	cmd1.Stderr = &stderrBuf
	cmd2.Stderr = &stderrBuf

	// Start jq first (it will block waiting for input from the pipe)
	if err := cmd2.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Start aliyun command (it will write to the pipe)
	if err := cmd1.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Wait for aliyun command to finish writing to the pipe
	if err := cmd1.Wait(); err != nil {
		return stdoutBuf.String(), fmt.Errorf("aliyun command failed: %w, stderr: %s", err, stderrBuf.String())
