package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport queries SLB information using aliyun CLI and jq,
// then exports the result to the specified output file.
// It returns the command output as a string and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Create the aliyun command: aliyun slb DescribeLoadBalancers --LoadBalancerName <name>
	cmdAliyun := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command: jq '.LoadBalancers.LoadBalancer[]'
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe to connect aliyun stdout to jq stdin
	stdoutPipe, err := cmdAliyun.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun command: %w", err)
	}
	cmdJq.Stdin = stdoutPipe

	// Buffer to capture jq output
	var outputBuffer bytes.Buffer
	cmdJq.Stdout = &outputBuffer

	// Start jq first so it's ready to consume the pipe
	if err := cmdJq.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Start the aliyun command
	if err := cmdAliyun.Start(); err != nil {
		// Ensure we wait for jq to avoid zombie process
		cmdJq.Wait()
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Wait for jq to finish processing the pipeline
	if err := cmdJq.Wait(); err != nil {
		// Ensure we wait for aliyun to avoid zombie process
		cmdAliyun.Wait()
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// Wait for aliyun to finish
	if err := cmdAliyun.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	result := outputBuffer.String()

	// Write the result to the output file
	if err := os.WriteFile(outputFile, []byte(result), 0644); err != nil {
		return "", fmt.Errorf("failed to write to output file %s: %w", outputFile, err)
	}

	return result, nil
}

func main() {
	// Example usage: go run main.go <LoadBalancerName> <OutputFile>
	if len(os.Args) != 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <loadBalancerName> <outputFile>\n", os.Args[0])
		os.Exit(1)
	}

	loadBalancerName := os.Args[1]
	outputFile := os.Args[2]

	result, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Successfully exported SLB information to %s\n", outputFile)
	fmt.Printf("Output size: %d bytes\n", len(result))
}

